import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Scenario plumbing
  it.todo("returns an empty results array when steps is empty");

  // Quote: main items
  it.todo("quotes a single sword for a brand-new customer with first-insurance surcharge and processing fee");
  it.todo("quotes an amulet using its base premium");
  it.todo("quotes a staff using its base premium");
  it.todo("quotes a potion using its base premium");

  // Quote: components and component blocks
  it.todo("quotes a single rune component at 25 G base premium");
  it.todo("quotes a block of 3 alike components at the special 60 G base premium");

  // Quote: modifiers
  it.todo("adds a 50% risk surcharge for cursed items");
  it.todo("adds a 30% risk surcharge for items with enchantment level >= 5");
  it.todo("applies a 20% loyalty discount for customers with >= 2 years with MHPCO");
  it.todo("applies a 15% discount on contracts after the first contract");
  it.todo("rounds the premium up in MHPCO's favor");

  // Claim
  it.todo("processes a claim by subtracting the 100 G deductible from the damage");
  it.todo("fully reimburses damage to items made of dragon material");
  it.todo("reimburses damage to items with enchantment level >= 8 at 50%");
  it.todo("caps total payout at twice the insurance sum and reports remaining cap");
});

