export interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export type Step = QuoteStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export type StepResult = QuoteResult;

export interface ScenarioResult {
  results: StepResult[];
}

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const base = BASE_PREMIUM_BY_TYPE[step.items[0].type];
    const premium = base * 1.1 + 5;
    return { premium };
  });
  return { results };
};

