import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Scenario plumbing
  it("returns an empty results array when steps is empty", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [],
    });
    expect(result).toEqual({ results: [] });
  });

  // Quote: main items
  it("quotes a single sword for a brand-new customer with first-insurance surcharge and processing fee", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
      ],
    });
    // Base 100 G * 1.10 (first insurance) + 5 G (processing) = 115 G
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes an amulet using its base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    // Base 60 G * 1.10 (first insurance) + 5 G (processing) = 71 G
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quotes a staff using its base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "staff", material: "wood", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    // Base 80 G * 1.10 + 5 G = 93 G
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quotes a potion using its base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "potion", material: "glass", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    // Base 40 G * 1.10 + 5 G = 49 G
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Quote: components and component blocks
  it("quotes a single rune component at 25 G base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune", material: "stone", enchantment: 1, cursed: false },
          ],
        },
      ],
    });
    // Base 25 G * 1.10 = 27.5 → ceil 28 G; + 5 G processing = 33 G
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it.todo("quotes a block of 3 alike components at the special 60 G base premium");

  // Quote: modifiers
  it.todo("adds a 50% risk surcharge for cursed items");
  it.todo("adds a 30% risk surcharge for items with enchantment level >= 5");
  it.todo("applies a 20% loyalty discount for customers with >= 2 years with MHPCO");
  it.todo("applies a 15% discount on contracts after the first contract");
  it.todo("rounds the premium up in MHPCO's favor");

  // Claim
  it.todo("processes a claim by subtracting the 100 G deductible from the damage");
  it.todo("fully reimburses damage to items made of dragon material");
  it.todo("reimburses damage to items with enchantment level >= 8 at 50%");
  it.todo("caps total payout at twice the insurance sum and reports remaining cap");
});

